#[async_trait]
impl<R: DeviceTrustProjectionRepository> DeviceTrustEventHandler for DeviceTrustProjector<R> {

    async fn on_created(&self, event: DeviceTrustCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = DeviceTrustProjection::new(
            event.id,
            event.user_id,
            event.device_fingerprint,
            event.device_name,
            event.device_type,
            event.trust_level,
            event.is_trusted,
            event.trusted_at,
            event.expires_at,
            event.last_used_at,
            event.usage_count,
            event.ip_address,
            event.location,
            event.risk_score,
            event.requires_mfa,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: DeviceTrustUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.device_fingerprint = event.device_fingerprint;
            projection.device_name = event.device_name;
            projection.device_type = event.device_type;
            projection.trust_level = event.trust_level;
            projection.is_trusted = event.is_trusted;
            projection.trusted_at = event.trusted_at;
            projection.expires_at = event.expires_at;
            projection.last_used_at = event.last_used_at;
            projection.usage_count = event.usage_count;
            projection.ip_address = event.ip_address;
            projection.location = event.location;
            projection.risk_score = event.risk_score;
            projection.requires_mfa = event.requires_mfa;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: DeviceTrustDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

